class Solution {
    public String concatHex36(int n) {
        int n2 = n * n;
        int n3 = n * n * n;
        String hex = Integer.toHexString(n2);
        StringBuilder base36 = new StringBuilder();
        while (n3 > 0) {
            int remainder = n3 % 36;
            if (remainder < 10) {
                base36.insert(0, remainder);
            } else {
                base36.insert(0, (char) ('A' + (remainder - 10)));
            }
            n3 /= 36;
        }
        return hex + base36.toString();
    }
}
